import{_ as o,o as r,c as t,a3 as s}from"./chunks/framework.CjquFG0V.js";const p=JSON.parse('{"title":"33. Hours Of Work","description":"","frontmatter":{"title":"33. Hours Of Work","eba":"Doctors in Training 2022-2026","topics":["education-pd","hours","employment","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/hours-of-work/33-hours-of-work.md","filePath":"ebas/doctors-in-training/hours-of-work/33-hours-of-work.md"}'),a={name:"ebas/doctors-in-training/hours-of-work/33-hours-of-work.md"};function n(i,e,h,l,d,u){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="_33-hours-of-work" tabindex="-1">33. Hours Of Work <a class="header-anchor" href="#_33-hours-of-work" aria-label="Permalink to &quot;33. Hours Of Work&quot;">​</a></h1><p><strong>33.1</strong> Ordinary Hours of Work per Week</p><p><strong>(a)</strong> Doctors other than Registrars</p><p>The ordinary hours of full time work will be 38 hours per week or an average of 38 hours per week over a period of up to four weeks.</p><p><strong>(b)</strong> Registrars</p><p><strong>(i)</strong> The ordinary hours of full-time work will be 38 hours plus five reasonable additional hours of Training Time (as defined at subclause 3.1(kk)) equalling 43 hours per week or an average of 43 hours per week over a period of up to four weeks.</p><p><strong>(ii)</strong> The arrangement of hours for Registrars is a long-standing industry arrangement that ensures Registrars have access to Training Time.</p><p><strong>(c)</strong> Work continuous except for meal break</p><p><strong>(i)</strong> A Doctor’s ordinary hours of work and any required extra work, excluding On-Call or Recall (<a href="/eba/ebas/doctors-in-training/hours-of-work/38-on-call.html">clauses 38</a> and 39), shall be continuous except for meal breaks.</p><p><strong>(ii)</strong> A meal break must be at least 30 minutes and is counted as time worked unless the Doctor is unavailable to answer calls during such break.</p><p><strong>(iii)</strong> A meal break should occur every 6 hours from commencement of the shift.</p><p><strong>33.2</strong> Maximum hours and consecutive shifts</p><p><strong>(a)</strong> A Doctor’s hours of work (not inclusive of periods of On-Call) must not exceed 140 hours in two roster weeks, or work more than seven consecutive night shifts unless:</p><p><strong>(i)</strong> the Doctor has given written consent to waive this entitlement; or</p><p><strong>(ii)</strong> a genuine medical emergency or disaster situation exists.</p><p><strong>(b)</strong> A Doctor who has exceeded, or is likely to exceed, the hours of work prescribed in subclause 33.2 as a result of the performance of unrostered overtime, the Doctor should, as soon as practicable, alert the Employer in accordance with subclause 41.2(b).</p><p><strong>(c)</strong> A Health Service will not be in breach of this clause where the Doctor applies for unrostered overtime after the relevant period expires.</p><p><strong>(d)</strong> The Health Service will endeavour to roster equitably having regard for all the circumstances including those of the Doctors and the needs of the organisation.</p><p><strong>33.3</strong> Hours per Day</p><p>Doctors must not be rostered for duty for more than 14 consecutive hours on any given shift unless, in the case of a Registrar, exceptional circumstances exist that require a greater shift length.</p><p><strong>33.4</strong> Minimum shift length</p><p>Full-time HMOs, MOs and SMOs must not be rostered for duty for less than four hours.</p><p><strong>33.5</strong> Averaging does not apply to overtime</p><p>Averaging of hours under this clause must not be utilised to reduce or avoid an entitlement prescribed in subclause 36.2 (Overtime Entitlement).</p><p><strong>33.6</strong> Breaks Between Ordinary Rostered Shifts</p><p><strong>(a)</strong> Doctors must be free from duty for at least 10 hours between rostered ordinary shifts.</p><p><strong>(b)</strong> To support clause 33.6(a), a Health Service should avoid rostering a Doctor for ordinary duty and standby On-Call consecutively (without a break) except where the period of standby On-Call and ordinary duty, taken together, do not exceed the maximum hours at 33.3. If it is unavoidable and does occur, the terms of 33.6(e) apply.</p><p><strong>(c)</strong> Doctors should be free from duty for at least forty-eight (48) hours when moving from night shifts to any other shift arrangement. If working a single night shift, Doctors must be free for at least twenty-three (23) hours.</p><p><strong>(d)</strong> Where a Doctor is on General On-Call or Stand-by On-Call and performs duty during an On-Call period (either by returning to their usual place of work or performing duty remotely), a Health Service must have regard to (a) above as well as the obligation to arrange work hours in a way that does not cause an excessive or unsafe work pattern to exist.</p><p><strong>(e)</strong> It is acknowledged that duty performed during an On-Call period may impact on occupational health and safety (including consecutive standby On-Call as described at 33.6(b)). As such, a Health Service must:</p><p><strong>(i)</strong> develop a procedure that addresses how occupational health and safety considerations are addressed where they arise (which may include but not be limited to later starting times, earlier finishing times, additional breaks) and expressly encourages Doctors to contact the relevant manager where they have not received a 10-hour break and it may impact on occupational health and safety;</p><p><strong>(ii)</strong> provide the procedure to all Doctors on General On-Call; and</p><p><strong>(iii)</strong> provide induction and training regarding the procedure to all Doctors on General On-Call.</p><p>Examples</p><p>A Doctor is rostered 7am to 6pm with the same roster the following day. Overnight the Doctor is ‘on call’ for the Health Service.</p><p>If after leaving the hospital the Doctor is disturbed by telephone calls and the last call is received at 11pm, the Doctor is entitled to have 10 hours off duty and is not required to present to the hospital before 9am the following day. The Doctor will work through to 6pm without loss of pay for the day.</p><p>If the same Doctor finishes at 6pm on day one and the last telephone call from the Health Service to the Doctor is received by 9pm on day one, the Doctor is required to start work at their normal starting time of 7am the next day.</p><p>If the same Doctor finishes at 6pm on day one and a call is received at 4.30am the following day, the Doctor has already received a 10 hour break and can start at their normal starting time of 7am.</p><p><strong>33.7</strong> Days Off per Fortnight</p><p><strong>(a)</strong> A Doctor must receive 3.5 days off work in each two week period (for a Doctor on night shift the word ‘days’ is replaced by the word ’nights’) as follows:</p><p><strong>(i)</strong> two days off must be consecutive;</p><p><strong>(ii)</strong> the remainder must be either 1.5 consecutive days off or three half days off.</p><p><strong>(b)</strong> One half day is defined as a period of at least four hours.</p><p>Plain language terms: ordinary hours.</p>',44)])])}const g=o(a,[["render",n]]);export{p as __pageData,g as default};
